package store

import (
	"time"
)

// ProtocolType defines the protocol type for ports
type ProtocolType string

const (
	// ProtocolHTTP is the HTTP protocol
	ProtocolHTTP ProtocolType = "HTTP"
	// ProtocolHTTPS is the HTTPS protocol
	ProtocolHTTPS ProtocolType = "HTTPS"
)

// TargetPort defines a port configuration
type TargetPort struct {
	PathPrefix string       `json:"pathPrefix,omitempty"`
	Name       string       `json:"name,omitempty"`
	Port       uint32       `json:"port"`
	Protocol   ProtocolType `json:"protocol"`
}

// EntryPoint defines an endpoint for accessing a sandbox
type EntryPoint struct {
	Path     string       `json:"path"`
	Protocol ProtocolType `json:"protocol"`
	Endpoint string       `json:"endpoint"`
}

// SandboxInfo contains metadata about a sandbox session
type SandboxInfo struct {
	SessionID        string        `json:"sessionId"`
	SandboxID        string        `json:"sandboxId"`
	Name             string        `json:"sandboxName"`
	Namespace        string        `json:"namespace"`
	Kind             string        `json:"kind"`
	EntryPoints      []EntryPoint  `json:"entryPoints"`
	CreatedAt        time.Time     `json:"createdAt"`
	ExpiresAt        time.Time     `json:"expiresAt"`
	LastActivity     time.Time     `json:"lastActivity"`
	Metadata         string        `json:"metadata,omitempty"`
	WarmPool         bool          `json:"warmPool,omitempty"`
	CodeInterpreterID string       `json:"codeInterpreterId,omitempty"`
}

