package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"time"

	"github.com/redis/go-redis/v9"
	"k8s.io/klog/v2"
)

const (
	sessionKeyPrefix = "session:"
	expiryZSETKey    = "session:expiry"
	activityZSETKey  = "session:last_activity"
)

// RedisStore implements Store interface using Redis
type RedisStore struct {
	client *redis.Client
}

// NewRedisStore creates a new Redis store
func NewRedisStore() (*RedisStore, error) {
	addr := os.Getenv("REDIS_ADDR")
	if addr == "" {
		return nil, errors.New("REDIS_ADDR environment variable is required")
	}

	password := os.Getenv("REDIS_PASSWORD")
	passwordRequired := os.Getenv("REDIS_PASSWORD_REQUIRED")
	if strings.ToLower(passwordRequired) != "false" && password == "" {
		return nil, errors.New("REDIS_PASSWORD environment variable is required (set REDIS_PASSWORD_REQUIRED=false to disable)")
	}

	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	})

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := client.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("failed to connect to Redis: %w", err)
	}

	klog.Info("Successfully connected to Redis")
	return &RedisStore{client: client}, nil
}

// Ping verifies connectivity
func (r *RedisStore) Ping(ctx context.Context) error {
	result, err := r.client.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

// GetSandboxBySessionID retrieves sandbox metadata
func (r *RedisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	key := sessionKeyPrefix + sessionID
	data, err := r.client.Get(ctx, key).Bytes()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var sandbox SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox data: %w", err)
	}

	return &sandbox, nil
}

// StoreSandbox persists sandbox metadata
func (r *RedisStore) StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return errors.New("ExpiresAt cannot be zero")
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox data: %w", err)
	}

	pipe := r.client.Pipeline()
	key := sessionKeyPrefix + sandbox.SessionID

	// Use SETNX for atomic creation
	pipe.SetNX(ctx, key, data, 0)

	// Add to expiry index
	pipe.ZAdd(ctx, expiryZSETKey, redis.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	})

	// Add to activity index
	activityTime := time.Now()
	if !sandbox.LastActivity.IsZero() {
		activityTime = sandbox.LastActivity
	}
	pipe.ZAdd(ctx, activityZSETKey, redis.Z{
		Score:  float64(activityTime.Unix()),
		Member: sandbox.SessionID,
	})

	// Execute pipeline atomically
	_, err = pipe.Exec(ctx)
	if err != nil {
		return fmt.Errorf("pipeline execution failed: %w", err)
	}

	return nil
}

// UpdateSandbox updates existing sandbox metadata
func (r *RedisStore) UpdateSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox data: %w", err)
	}

	key := sessionKeyPrefix + sandbox.SessionID
	result, err := r.client.Set(ctx, key, data, 0).Result()
	if err != nil {
		return err
	}
	if result != "OK" {
		return errors.New("key not exists")
	}

	return nil
}

// DeleteSandboxBySessionID removes sandbox by session ID
func (r *RedisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKeyPrefix + sessionID

	pipe := r.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, expiryZSETKey, sessionID)
	pipe.ZRem(ctx, activityZSETKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

// ListExpiredSandboxes returns session IDs expired before given time
func (r *RedisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	result, err := r.client.ZRangeByScore(ctx, expiryZSETKey, &redis.ZRangeBy{
		Min:    "-inf",
		Max:    fmt.Sprintf("%d", before.Unix()),
		Count:  int64(limit),
		Offset: 0,
	}).Result()
	if err != nil {
		return nil, err
	}
	return result, nil
}

// ListInactiveSandboxes returns session IDs inactive before given time
func (r *RedisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	result, err := r.client.ZRangeByScore(ctx, activityZSETKey, &redis.ZRangeBy{
		Min:    "-inf",
		Max:    fmt.Sprintf("%d", before.Unix()),
		Count:  int64(limit),
		Offset: 0,
	}).Result()
	if err != nil {
		return nil, err
	}
	return result, nil
}

// UpdateSessionLastActivity updates the last activity timestamp
func (r *RedisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("session ID cannot be empty")
	}

	if at.IsZero() {
		at = time.Now()
	}

	key := sessionKeyPrefix + sessionID
	exists, err := r.client.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	return r.client.ZAdd(ctx, activityZSETKey, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Err()
}

// Close closes the Redis connection
func (r *RedisStore) Close() error {
	return r.client.Close()
}

