func (r *RedisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKeyPrefix + sessionID

	pipe := r.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, expiryZSETKey, sessionID)
	pipe.ZRem(ctx, activityZSETKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

// ListExpiredSandboxes returns session IDs expired before given time
func (r *RedisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	result, err := r.client.ZRangeByScore(ctx, expiryZSETKey, &redis.ZRangeBy{
		Min:    "-inf",
		Max:    fmt.Sprintf("%d", before.Unix()),
		Count:  int64(limit),
		Offset: 0,
	}).Result()
	if err != nil {
		return nil, err
	}
	return result, nil
}

// ListInactiveSandboxes returns session IDs inactive before given time
func (r *RedisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	result, err := r.client.ZRangeByScore(ctx, activityZSETKey, &redis.ZRangeBy{
		Min:    "-inf",
		Max:    fmt.Sprintf("%d", before.Unix()),
		Count:  int64(limit),
		Offset: 0,
	}).Result()
	if err != nil {
		return nil, err
	}
	return result, nil
}

// UpdateSessionLastActivity updates the last activity timestamp
func (r *RedisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("session ID cannot be empty")
	}

	if at.IsZero() {
		at = time.Now()
	}

	key := sessionKeyPrefix + sessionID
	exists, err := r.client.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	return r.client.ZAdd(ctx, activityZSETKey, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Err()
}

// Close closes the Redis connection
func (r *RedisStore) Close() error {
	return r.client.Close()
}

