package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"k8s.io/klog/v2"
)

// ValkeyStore implements Store interface using Valkey
type ValkeyStore struct {
	client valkey.Client
}

// NewValkeyStore creates a new Valkey store
func NewValkeyStore() (*ValkeyStore, error) {
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		return nil, errors.New("VALKEY_ADDR environment variable is required")
	}

	password := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := os.Getenv("VALKEY_PASSWORD_REQUIRED")
	if strings.ToLower(passwordRequired) != "false" && password == "" {
		return nil, errors.New("VALKEY_PASSWORD environment variable is required (set VALKEY_PASSWORD_REQUIRED=false to disable)")
	}

	options := []valkey.ClientOption{
		valkey.WithInitAddress(strings.Split(addr, ",")...),
	}

	if password != "" {
		options = append(options, valkey.WithPassword(password))
	}

	if os.Getenv("VALKEY_DISABLE_CACHE") == "true" {
		options = append(options, valkey.WithDisableCache())
	}

	if os.Getenv("VALKEY_FORCE_SINGLE") == "true" {
		options = append(options, valkey.WithForceSingleClient())
	}

	client, err := valkey.NewClient(options...)
	if err != nil {
		return nil, fmt.Errorf("failed to create Valkey client: %w", err)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := client.Do(ctx, client.B().Ping().Build()).Error(); err != nil {
		return nil, fmt.Errorf("failed to connect to Valkey: %w", err)
	}

	klog.Info("Successfully connected to Valkey")
	return &ValkeyStore{client: client}, nil
}

// Ping verifies connectivity
func (v *ValkeyStore) Ping(ctx context.Context) error {
	result := v.client.Do(ctx, v.client.B().Ping().Build())
	if err := result.Error(); err != nil {
		return err
	}
	response, err := result.ToString()
	if err != nil {
		return err
	}
	if response != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", response)
	}
	return nil
}

// GetSandboxBySessionID retrieves sandbox metadata
func (v *ValkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	key := sessionKeyPrefix + sessionID
	result := v.client.Do(ctx, v.client.B().Get().Key(key).Build())
	if err := result.Error(); err != nil {
		if valkey.IsValkeyNil(err) {
			return nil, ErrNotFound
		}
		return nil, err
	}

	data, err := result.AsBytes()
	if err != nil {
		return nil, err
	}

	var sandbox SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox data: %w", err)
	}

	return &sandbox, nil
}

// StoreSandbox persists sandbox metadata
func (v *ValkeyStore) StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return errors.New("ExpiresAt cannot be zero")
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox data: %w", err)
	}

	key := sessionKeyPrefix + sandbox.SessionID

	// SETNX for atomic creation
	setNX := v.client.B().Set().Key(key).Value(string(data)).Nx().Build()
	if err := v.client.Do(ctx, setNX).Error(); err != nil {
		return fmt.Errorf("SETNX failed: %w", err)
	}

	// Add to expiry index
	activityTime := time.Now()
	if !sandbox.LastActivity.IsZero() {
		activityTime = sandbox.LastActivity
	}

	expiryZAdd := v.client.B().Zadd().Key(expiryZSETKey).ScoreMember().Score(float64(sandbox.ExpiresAt.Unix())).Member(sandbox.SessionID).Build()
	if err := v.client.Do(ctx, expiryZAdd).Error(); err != nil {
		return fmt.Errorf("ZADD expiry failed: %w", err)
	}

	activityZAdd := v.client.B().Zadd().Key(activityZSETKey).ScoreMember().Score(float64(activityTime.Unix())).Member(sandbox.SessionID).Build()
	if err := v.client.Do(ctx, activityZAdd).Error(); err != nil {
		return fmt.Errorf("ZADD activity failed: %w", err)
	}

	return nil
}

// UpdateSandbox updates existing sandbox metadata
func (v *ValkeyStore) UpdateSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}

	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox data: %w", err)
	}

	key := sessionKeyPrefix + sandbox.SessionID
	result := v.client.Do(ctx, v.client.B().Set().Key(key).Value(string(data)).Xx().Build())
	if err := result.Error(); err != nil {
		return err
	}
	if !result.IsSuccess() {
		return errors.New("key not exists")
	}

	return nil
}

// DeleteSandboxBySessionID removes sandbox by session ID
func (v *ValkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKeyPrefix + sessionID

	// Delete session key
	delCmd := v.client.B().Del().Key(key).Build()
	if err := v.client.Do(ctx, delCmd).Error(); err != nil {
		return err
	}

	// Remove from expiry ZSET
	zremExpiry := v.client.B().Zrem().Key(expiryZSETKey).Member(sessionID).Build()
	if err := v.client.Do(ctx, zremExpiry).Error(); err != nil {
		return err
	}

	// Remove from activity ZSET
	zremActivity := v.client.B().Zrem().Key(activityZSETKey).Member(sessionID).Build()
	if err := v.client.Do(ctx, zremActivity).Error(); err != nil {
		return err
	}

	return nil
}

// ListExpiredSandboxes returns session IDs expired before given time
func (v *ValkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	result := v.client.Do(ctx, v.client.B().Zrangebyscore().Key(expiryZSETKey).
		Min("-inf").Max(fmt.Sprintf("%d", before.Unix())).
		Count(int64(limit)).Offset(0).Build())
	if err := result.Error(); err != nil {
		return nil, err
	}

	return result.ToStringSlice()
}

// ListInactiveSandboxes returns session IDs inactive before given time
func (v *ValkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]string, error) {
	result := v.client.Do(ctx, v.client.B().Zrangebyscore().Key(activityZSETKey).
		Min("-inf").Max(fmt.Sprintf("%d", before.Unix())).
		Count(int64(limit)).Offset(0).Build())
	if err := result.Error(); err != nil {
		return nil, err
	}

	return result.ToStringSlice()
}

// UpdateSessionLastActivity updates the last activity timestamp
func (v *ValkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("session ID cannot be empty")
	}

	if at.IsZero() {
		at = time.Now()
	}

	key := sessionKeyPrefix + sessionID
	exists := v.client.Do(ctx, v.client.B().Exists().Key(key).Build())
	count, err := exists.ToInt64()
	if err != nil {
		return err
	}
	if count == 0 {
		return ErrNotFound
	}

	zadd := v.client.B().Zadd().Key(activityZSETKey).ScoreMember().Score(float64(at.Unix())).Member(sessionID).Build()
	return v.client.Do(ctx, zadd).Error()
}

// Close closes the Valkey connection
func (v *ValkeyStore) Close() error {
	return v.client.Close()
}

