// APIErrorResponse represents a standardized error response
type APIErrorResponse struct {
	Error   string `json:"error"`
	Code    int    `json:"code,omitempty"`
	Detail  string `json:"detail,omitempty"`
	Message string `json:"message,omitempty"`
}

// WriteErrorResponse writes an error response to the client
func WriteErrorResponse(w http.ResponseWriter, err error, defaultCode int) {
	status := defaultCode
	message := err.Error()

	if apierrors.IsNotFound(err) {
		status = http.StatusNotFound
	} else if apierrors.IsBadRequest(err) {
		status = http.StatusBadRequest
	} else if apierrors.IsUnauthorized(err) {
		status = http.StatusUnauthorized
	} else if apierrors.IsForbidden(err) {
		status = http.StatusForbidden
	} else if apierrors.IsConflict(err) {
		status = http.StatusConflict
	} else if apierrors.IsTimeout(err) {
		status = http.StatusRequestTimeout
	} else if apierrors.IsServiceUnavailable(err) {
		status = http.StatusServiceUnavailable
	}

	// Extract detail if available
	var detail string
	if statusErr, ok := err.(apierrors.APIStatus); ok {
		if code := statusErr.Status().Code; code != 0 {
			status = int(code)
		}
		if statusErr.Status().Message != "" {
			message = statusErr.Status().Message
		}
		if len(statusErr.Status().Details) > 0 {
			detail = statusErr.Status().Details[0].Message
		}
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	response := APIErrorResponse{
		Error:   message,
		Code:    status,
		Detail:  detail,
		Message: message,
	}
	fmt.Fprintf(w, `{"error":"%s"}`, message)
}

